// Script para generar un formulario que permite a los usuarios introducir texto y guardarlo
document.addEventListener("DOMContentLoaded", function () {
  const form = document.createElement("form");
  form.setAttribute("id", "textoForm");

  const label = document.createElement("label");
  label.setAttribute("for", "textoInput");
  label.textContent = "Introduce tu texto:";

  const input = document.createElement("input");
  input.setAttribute("type", "text");
  input.setAttribute("id", "textoInput");
  input.setAttribute("name", "textoInput");
  input.setAttribute("placeholder", "Escribe aquí...");

  const button = document.createElement("button");
  button.setAttribute("type", "button");
  button.textContent = "Guardar texto";

  // Agregar elementos al formulario
  form.appendChild(label);
  form.appendChild(input);
  form.appendChild(button);

  // Agregar el formulario al cuerpo del documento
  document.body.appendChild(form);

  // Función para guardar el texto
  button.addEventListener("click", function () {
    const texto = input.value.trim();
    if (texto === "") {
      alert("Por favor, introduce un texto válido.");
      return;
    }

    // Guardar el texto en el almacenamiento local del navegador
    localStorage.setItem("usuarioTexto", texto);
    alert("Texto guardado correctamente.");
  });
});
